import{_ as t,o,c as r,ae as a}from"./chunks/framework.EHGTsUvI.js";const g=JSON.parse('{"title":"概述","description":"","frontmatter":{},"headers":[],"relativePath":"cn/guide/about.md","filePath":"cn/guide/about.md"}'),n={name:"cn/guide/about.md"};function i(c,e,s,d,p,l){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h1><p>Semantic-TypeScript 是流处理技术的一次重大飞跃，它<strong>集大成</strong>了 JavaScript <code>GeneratorFunction</code>、Java Streams 和 MySQL 式索引中最有效的概念。其核心理念既简单又强大：通过智能索引而非暴力迭代，来构建高效的数据处理管道。</p><p>当传统库强制使用同步循环或笨拙的 Promise 链时，Semantic-TypeScript 提供了一种<strong>完全异步</strong>、函数式纯粹且类型安全的体验，专为现代前端开发的需求而设计。</p><p>在其优雅的模型中，数据仅在上游管道显式调用 <code>accept</code>（以及可选的 <code>interrupt</code>）回调时才会抵达消费者。您完全掌控时机——就在您需要的时候。</p><h2 id="开发者为何青睐它" tabindex="-1">开发者为何青睐它 <a class="header-anchor" href="#开发者为何青睐它" aria-label="Permalink to &quot;开发者为何青睐它&quot;">​</a></h2><ul><li><strong>零样板索引</strong> — 每个元素都携带其自然或自定义索引。</li><li><strong>函数式纯粹风格</strong> — 具备完整的 TypeScript 类型推断。</li><li><strong>防泄漏事件流</strong> — <code>useWindow</code>、<code>useDocument</code>、<code>useHTMLElement</code> 和 <code>useWebSocket</code> 在设计时就考虑了安全性。您通过 <code>limit(n)</code>、<code>sub(start, end)</code> 或 <code>takeWhile(predicate)</code> 定义边界，库则负责清理。没有残留的监听器，没有内存泄漏。</li><li><strong>开箱即用的统计</strong> — 全面的数值和 bigint 分析，包括平均值、中位数、众数、方差、偏度和峰度。</li><li><strong>可预测的性能</strong> — 根据需求在有序和无序收集器之间选择。</li><li><strong>内存高效</strong> — 流采用惰性求值，无需担心内存问题。</li><li><strong>无未定义行为</strong> — TypeScript 保证类型安全和可空性。除非在回调函数中显式修改，否则输入数据保持不变。</li></ul><h2 id="准备探索" tabindex="-1">准备探索？ <a class="header-anchor" href="#准备探索" aria-label="Permalink to &quot;准备探索？&quot;">​</a></h2><p>Semantic-TypeScript 将复杂的数据流转化为可读、可组合且高性能的管道。无论您是处理实时 UI 事件、处理大型数据集还是构建分析仪表板，它都能提供数据库级索引的强大功能与函数式编程的优雅。</p><p><strong>Semantic-TypeScript</strong> — 流与结构的交汇点。</p><p>立即开始构建，体验精心设计的索引所带来的不同。</p><p><strong>构建清晰，运行自信，让数据流转尽在掌控。</strong></p>',11)])])}const m=t(n,[["render",i]]);export{g as __pageData,m as default};
